import React, { Component } from 'react';
import Logo from '../assets/images/ahmet-cetinkaya-logo.svg';
import '../assets/scss/pages/maintenance-page.scss';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faInstagram, faTwitter, faGithub, faLinkedin, faBehance } from '@fortawesome/free-brands-svg-icons';

class Maintenance extends Component {
  state = {
    progress: 5,
  };
  render() {
    const { progress } = this.state;

    return (
      <div id='maintenance-page'>
        <div class='container box'>
          <header className='row p-md-5'>
            <div className='col-md-8 text-center text-md-start my-5 m-md-0'>
              <img className='logo' src={Logo} alt='Ahmet Çetinkaya Logo' />
            </div>
            <div id='social-links' className='col-md-4 d-flex justify-content-around'>
              <a href='https://www.instagram.com/ahmetcetinkaya.png/' alt='ahmet çetinkaya instagram' target='_blank' rel='noreferrer'>
                <FontAwesomeIcon icon={faInstagram}></FontAwesomeIcon>
              </a>
              <a href='https://twitter.com/ahmetctnky_txt' alt='ahmet çetinkaya twitter' target='_blank' rel='noreferrer'>
                <FontAwesomeIcon icon={faTwitter}></FontAwesomeIcon>
              </a>
              <a href='https://www.linkedin.com/in/ahmet-cetinkaya/' alt='ahmet çetinkaya linkedin' target='_blank' rel='noreferrer'>
                <FontAwesomeIcon icon={faLinkedin}></FontAwesomeIcon>
              </a>
              <a href='https://github.com/ahmet-cetinkaya' alt='ahmet çetinkaya github' target='_blank' rel='noreferrer'>
                <FontAwesomeIcon icon={faGithub}></FontAwesomeIcon>
              </a>
              <a href='https://www.behance.net/ahmetcetinkaya' alt='ahmet çetinkaya behance' target='_blank' rel='noreferrer'>
                <FontAwesomeIcon icon={faBehance}></FontAwesomeIcon>
              </a>
            </div>
          </header>
          <section className='row'>
            <div className='col-12 text-center'>
              <h1 className='display-1 text-white'>Yakında</h1>
              <div className='progress mt-5'>
                <div className='progress-bar bg-warning' role='progressbar' style={{ width: `${progress}%` }} aria-valuenow={progress} aria-valuemin='0' aria-valuemax='100'>
                  <span className='progress-text'>%{progress}</span>
                </div>
              </div>
            </div>
          </section>
          {/* <footer className='text-muted'>© Copyright {new Date().getFullYear()} - Ahmet Çetinkaya</footer> */}
        </div>
      </div>
    );
  }
}

export default Maintenance;
