import React, { Component } from 'react';
import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Maintenance from './pages/Maintenance';

class App extends Component {
  render() {
    return (
      <div id='App'>
        <Router>
          <Switch>
            <Route path='/'>
              <Maintenance />
            </Route>
          </Switch>
        </Router>
      </div>
    );
  }
}

export default App;
